class Solution(object):
    def calculateScore(self, s):
        stacks = [[] for _ in range(26)]
        score = 0
        for i, c in enumerate(s):
            ci = ord(c) - ord('a')
            mirror_i = 25 - ci  # 'a'<->z', 'b'<->'y', etc.
            if stacks[mirror_i]:
                j = stacks[mirror_i].pop()
                score += i - j
            else:
                stacks[ci].append(i)
        return score
